//! gnosis-engine-core — the jet-engine **compressor cascade**, shared by the three runtime
//! instantiations of `Gnosis.MathJetEngine`: FOIL (`distributed-inference`), gnosis-uring
//! (`open-source/x-gnosis`), and — mirrored in TypeScript — aether wasm-simd.
//!
//! A runtime pipeline is a list of [`Stage`]s, each carrying a *measured* speedup / compression
//! ratio. The jet engine's compressor law says the pipeline's overall ratio is the **product** of
//! its stage ratios ([`overall_ratio`]), and stacking two pipelines **multiplies** their ratios —
//! the `(List, ++) -> (·, ×)` monoid homomorphism ([`compose`] + [`homomorphism_holds`]).
//!
//! Proof backing (gnosis-math, axiom-clean):
//!   * `Gnosis.MathJetEngine.overallRatio`          — overall ratio = product of stages
//!   * `Gnosis.MathJetEngine.overallRatio_append`   — stacking multiplies (Nat)
//!   * `Gnosis.CompressorCascadeRuntime.prodOver_append` — stacking multiplies (any monoid; covers
//!                                                    the measured rational/float ratios used here)
//!   * `Gnosis.MathJetEngine.jet_is_steady_ripcord` — the cascade product is the ripcord spin
//!
//! Scope: the compressor cascade only. The spool steady-state governor and additive turbofan
//! thrust laws are intentionally not modeled here.

pub mod ballistic;
pub mod speed_of_light;

/// Canonical Lean theorem IDs backing this cascade — the single source of truth the benches cite.
pub const MATH_JET_ENGINE_MASTER_THEOREM_ID: &str = "Gnosis.MathJetEngine.math_jet_engine_master";
pub const OVERALL_RATIO_APPEND_THEOREM_ID: &str = "Gnosis.MathJetEngine.overallRatio_append";
pub const JET_IS_STEADY_RIPCORD_THEOREM_ID: &str = "Gnosis.MathJetEngine.jet_is_steady_ripcord";
pub const PRODOVER_APPEND_THEOREM_ID: &str = "Gnosis.CompressorCascadeRuntime.prodOver_append";
pub const RUNTIME_CASCADE_THEOREM_ID: &str =
    "Gnosis.CompressorCascadeRuntime.runtime_compressor_cascade_composes";

/// The theorem-ID set every cascade report carries.
pub const CASCADE_THEOREM_IDS: [&str; 5] = [
    MATH_JET_ENGINE_MASTER_THEOREM_ID,
    OVERALL_RATIO_APPEND_THEOREM_ID,
    JET_IS_STEADY_RIPCORD_THEOREM_ID,
    PRODOVER_APPEND_THEOREM_ID,
    RUNTIME_CASCADE_THEOREM_ID,
];

/// The E₈ Coxeter number — the overall ratio of the canonical `[2,3,5]` compressor.
pub const E8_COXETER_NUMBER: f64 = 30.0;

/// A compressor stage: a named pipeline transform with a measured ratio.
///
/// `ratio` is the stage's speedup / compression factor in isolation (`> 1.0` accelerates,
/// `1.0` is a clean pass-through — the identity of the cascade).
#[derive(Clone, Debug, PartialEq)]
pub struct Stage {
    pub name: String,
    pub ratio: f64,
}

impl Stage {
    pub fn new(name: impl Into<String>, ratio: f64) -> Self {
        Self { name: name.into(), ratio }
    }
}

/// Overall pressure ratio of a stack = **product** of the stage ratios.
///
/// Mirrors `Gnosis.MathJetEngine.overallRatio` (`prodOver (·*·) 1`). The empty cascade is a clean
/// pass-through with ratio `1.0` (the identity).
pub fn overall_ratio(stages: &[Stage]) -> f64 {
    stages.iter().map(|s| s.ratio).product()
}

/// **Append homomorphism**: stacking two compressors concatenates their stage lists, so that
/// `overall_ratio(compose(a, b)) == overall_ratio(a) * overall_ratio(b)`.
///
/// Mirrors `Gnosis.MathJetEngine.overallRatio_append`.
pub fn compose(a: &[Stage], b: &[Stage]) -> Vec<Stage> {
    let mut v = Vec::with_capacity(a.len() + b.len());
    v.extend_from_slice(a);
    v.extend_from_slice(b);
    v
}

/// The append homomorphism holds within relative tolerance `tol`:
/// `|overall(compose(a,b)) - overall(a)·overall(b)| <= tol · max(overall(compose(a,b)), 1)`.
pub fn homomorphism_holds(a: &[Stage], b: &[Stage], tol: f64) -> bool {
    let lhs = overall_ratio(&compose(a, b));
    let rhs = overall_ratio(a) * overall_ratio(b);
    (lhs - rhs).abs() <= tol * lhs.abs().max(1.0)
}

/// A measured cascade report — the honest per-stage-vs-composed record a bench fills in.
///
/// `predicted_product` is the design-law prediction (product of the **isolated** stage ratios);
/// `measured_end_to_end` is the **real** composed speedup measured on the full pipeline. The
/// residual `measured / predicted` is `1.0` when the product law predicts the pipeline exactly.
#[derive(Clone, Debug)]
pub struct CascadeReport {
    pub label: String,
    pub stages: Vec<Stage>,
    pub predicted_product: f64,
    pub measured_end_to_end: f64,
    pub theorem_ids: &'static [&'static str],
}

impl CascadeReport {
    pub fn new(label: impl Into<String>, stages: Vec<Stage>, measured_end_to_end: f64) -> Self {
        let predicted_product = overall_ratio(&stages);
        Self {
            label: label.into(),
            stages,
            predicted_product,
            measured_end_to_end,
            theorem_ids: &CASCADE_THEOREM_IDS,
        }
    }

    /// Residual = measured / predicted (`1.0` ⇒ the product law predicts end-to-end exactly).
    pub fn residual(&self) -> f64 {
        if self.predicted_product == 0.0 {
            0.0
        } else {
            self.measured_end_to_end / self.predicted_product
        }
    }

    /// The product law predicts the measured end-to-end speedup within relative tolerance `tol`.
    pub fn law_holds(&self, tol: f64) -> bool {
        (self.measured_end_to_end - self.predicted_product).abs()
            <= tol * self.predicted_product.abs().max(1.0)
    }

    /// A one-line, emoji-free summary for bench output.
    pub fn summary(&self) -> String {
        let stages: Vec<String> =
            self.stages.iter().map(|s| format!("{}={:.3}x", s.name, s.ratio)).collect();
        format!(
            "{}: stages[{}] predicted={:.4}x measured={:.4}x residual={:.3}",
            self.label,
            stages.join(" * "),
            self.predicted_product,
            self.measured_end_to_end,
            self.residual()
        )
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn empty_cascade_is_identity() {
        assert_eq!(overall_ratio(&[]), 1.0);
    }

    #[test]
    fn canonical_e8_cascade_is_30() {
        // [2,3,5] -> overall ratio 30 = h(E8), mirroring MathJetEngine.e8_overall_ratio.
        let s = vec![Stage::new("2", 2.0), Stage::new("3", 3.0), Stage::new("5", 5.0)];
        assert_eq!(overall_ratio(&s), E8_COXETER_NUMBER);
    }

    #[test]
    fn two_spool_turbofan_append_homomorphism() {
        // Low spool [2,3] (ratio 6) feeding high spool [5] (ratio 5) composes to 30 — the
        // overallRatio_append law, the two-spool turbofan.
        let low = vec![Stage::new("low2", 2.0), Stage::new("low3", 3.0)];
        let high = vec![Stage::new("high5", 5.0)];
        assert_eq!(overall_ratio(&low), 6.0);
        assert_eq!(overall_ratio(&high), 5.0);
        assert_eq!(overall_ratio(&compose(&low, &high)), 30.0);
        assert_eq!(
            overall_ratio(&compose(&low, &high)),
            overall_ratio(&low) * overall_ratio(&high)
        );
        assert!(homomorphism_holds(&low, &high, 1e-9));
    }

    #[test]
    fn measured_rational_ratios_compose() {
        // Measured (non-integer) stage ratios still obey the homomorphism — the monoid-general
        // prodOver_append law over rationals/floats.
        let a = vec![Stage::new("cache", 2.5), Stage::new("simd", 4.0)];
        let b = vec![Stage::new("quant", 1.8)];
        assert!(homomorphism_holds(&a, &b, 1e-9));
        assert!((overall_ratio(&compose(&a, &b)) - 18.0).abs() < 1e-9);
    }

    #[test]
    fn report_law_holds_and_residual() {
        let stages = vec![Stage::new("cache", 2.5), Stage::new("simd", 4.0)];
        let r = CascadeReport::new("test", stages, 10.0); // predicted 10.0
        assert!(r.law_holds(1e-9));
        assert!((r.residual() - 1.0).abs() < 1e-9);
        assert_eq!(r.theorem_ids.len(), 5);
    }
}
